33	// this function receives 2 pointers (indicated by *) so it can set their values
34	void getColors(uint8_t value, uint8_t scheme, uint8_t *foreground, uint8_t *background)
35	// scheme must be a valid index into the table of 4 schemes
36	__CPROVER_requires(scheme < 4)
37	// both output pointers must point to writable bytes
38	__CPROVER_requires(__CPROVER_w_ok(foreground, sizeof(uint8_t)))
39	__CPROVER_requires(__CPROVER_w_ok(background, sizeof(uint8_t)))
40	__CPROVER_assigns(*foreground, *background)
41	// the exact bytes written: odd table index for foreground, even index for background
42	__CPROVER_ensures(*foreground == COLOR_SCHEMES_TABLE[scheme][(1 + value * 2) % 32])
43	__CPROVER_ensures(*background == COLOR_SCHEMES_TABLE[scheme][(0 + value * 2) % 32])
44	{
45		uint8_t original[] = {8, 255, 1, 255, 2, 255, 3, 255, 4, 255, 5, 255, 6, 255, 7, 255, 9, 0, 10, 0, 11, 0, 12, 0, 13, 0, 14, 0, 255, 0, 255, 0};
46		uint8_t blackwhite[] = {232, 255, 234, 255, 236, 255, 238, 255, 240, 255, 242, 255, 244, 255, 246, 0, 248, 0, 249, 0, 250, 0, 251, 0, 252, 0, 253, 0, 254, 0, 255, 0};
47		uint8_t bluered[] = {235, 255, 63, 255, 57, 255, 93, 255, 129, 255, 165, 255, 201, 255, 200, 255, 199, 255, 198, 255, 197, 255, 196, 255, 196, 255, 196, 255, 196, 255, 196, 255};
48		uint8_t whiteblack[] = {255, 0, 254, 0, 253, 0, 252, 0, 251, 0, 250, 0, 249, 0, 248, 0, 246, 255, 244, 255, 242, 255, 240, 255, 238, 255, 236, 255, 234, 255, 232, 255};
49		uint8_t *schemes[] = {original, blackwhite, bluered, whiteblack};
50		// modify the 'pointed to' variables (using a * on the left hand of the assignment)
51		*foreground = *(schemes[scheme] + (1 + value * 2) % sizeof(original));
52		*background = *(schemes[scheme] + (0 + value * 2) % sizeof(original));
53		// alternatively we could have returned a struct with two variables
54	}
55	
56	uint8_t getDigitCount(uint32_t number)
57	{
58		uint8_t count = 0;
59		do
60		{
61			number /= 10;
62			count += 1;
63		} while (number);
64		return count;
65	}
66	
67	void drawBoard(uint8_t board[SIZE][SIZE], uint8_t scheme, uint32_t score)
68	{
69		uint8_t x, y, fg, bg;
70		printf("\033[H"); // move cursor to 0,0
71		printf("2048.c %17u pts\n\n", score);
72		for (y = 0; y < SIZE; y++)
73		{
74			for (x = 0; x < SIZE; x++)
75			{
76				// send the addresses of the foreground and background variables,
77				// so that they can be modified by the getColors function
78				getColors(board[x][y], scheme, &fg, &bg);
79				printf("\033[38;5;%u;48;5;%um", fg, bg); // set color
80				printf("       ");
81				printf("\033[m"); // reset all modes
82			}
83			printf("\n");
84			for (x = 0; x < SIZE; x++)
85			{
86				getColors(board[x][y], scheme, &fg, &bg);
87				printf("\033[38;5;%u;48;5;%um", fg, bg); // set color
88				if (board[x][y] != 0)
89				{
90					uint32_t number = 1 << board[x][y];
91					uint8_t t = 7 - getDigitCount(number);
92					printf("%*s%u%*s", t - t / 2, "", number, t / 2, "");
93				}
94				else
95				{
96					printf("   ·   ");
97				}
98				printf("\033[m"); // reset all modes
99			}
100			printf("\n");
101			for (x = 0; x < SIZE; x++)
102			{
103				getColors(board[x][y], scheme, &fg, &bg);
104				printf("\033[38;5;%u;48;5;%um", fg, bg); // set color
105				printf("       ");
106				printf("\033[m"); // reset all modes
107			}
108			printf("\n");
109		}
110		printf("\n");
111		printf("        ←,↑,→,↓ or q        \n");
112		printf("\033[A"); // one line up
113	}
114	
115	uint8_t findTarget(uint8_t array[SIZE], uint8_t x, uint8_t stop)
116	{
117		uint8_t t;
118		// if the position is already on the first, don't evaluate
119		if (x == 0)
120		{
121			return x;
122		}
123		for (t = x - 1;; t--)
124		{
125			if (array[t] != 0)
126			{
127				if (array[t] != array[x])
128				{
129					// merge is not possible, take next position
130					return t + 1;
131				}
132				return t;
133			}
134			else
135			{
136				// we should not slide further, return this one
137				if (t == stop)
138				{
139					return t;
140				}
141			}
142		}
143		// we did not find a target
144		return x;
145	}
146	
147	bool slideArray(uint8_t array[SIZE], uint32_t *score)
148	{
149		bool success = false;
150		uint8_t x, t, stop = 0;
151	
152		for (x = 0; x < SIZE; x++)
153		{
154			if (array[x] != 0)
155			{
156				t = findTarget(array, x, stop);
157				// if target is not original position, then move or merge
158				if (t != x)
159				{
160					// if target is zero, this is a move
161					if (array[t] == 0)
162					{
163						array[t] = array[x];
164					}
165					else if (array[t] == array[x])
166					{
167						// merge (increase power of two)
168						array[t]++;
169						// increase score
170						*score += 1 << array[t];
171						// set stop to avoid double merge
172						stop = t + 1;
173					}
174					array[x] = 0;
175					success = true;
176				}
177			}
178		}
179		return success;
180	}
181	
182	void rotateBoard(uint8_t board[SIZE][SIZE])
183	{
184		uint8_t i, j, n = SIZE;
185		uint8_t tmp;
186		for (i = 0; i < n / 2; i++)
187		{
188			for (j = i; j < n - i - 1; j++)
189			{
190				tmp = board[i][j];
191				board[i][j] = board[j][n - i - 1];
192				board[j][n - i - 1] = board[n - i - 1][n - j - 1];
193				board[n - i - 1][n - j - 1] = board[n - j - 1][i];
194				board[n - j - 1][i] = tmp;
195			}
196		}
197	}
198	
199	bool moveUp(uint8_t board[SIZE][SIZE], uint32_t *score)
200	{
201		bool success = false;
202		uint8_t x;
203		for (x = 0; x < SIZE; x++)
204		{
205			success |= slideArray(board[x], score);
206		}
207		return success;
208	}
209	
210	bool moveLeft(uint8_t board[SIZE][SIZE], uint32_t *score)
211	{
212		bool success;
213		rotateBoard(board);
214		success = moveUp(board, score);
215		rotateBoard(board);
216		rotateBoard(board);
217		rotateBoard(board);
218		return success;
219	}
220	
221	bool moveDown(uint8_t board[SIZE][SIZE], uint32_t *score)
222	{
223		bool success;
224		rotateBoard(board);
225		rotateBoard(board);
226		success = moveUp(board, score);
227		rotateBoard(board);
228		rotateBoard(board);
229		return success;
230	}
231	
232	bool moveRight(uint8_t board[SIZE][SIZE], uint32_t *score)
233	{
234		bool success;
235		rotateBoard(board);
236		rotateBoard(board);
237		rotateBoard(board);
238		success = moveUp(board, score);
239		rotateBoard(board);
240		return success;
241	}
242	
243	bool findPairDown(uint8_t board[SIZE][SIZE])
244	{
245		bool success = false;
246		uint8_t x, y;
247		for (x = 0; x < SIZE; x++)
248		{
249			for (y = 0; y < SIZE - 1; y++)
250			{
251				if (board[x][y] == board[x][y + 1])
252					return true;
253			}
254		}
255		return success;
256	}
257	
258	uint8_t countEmpty(uint8_t board[SIZE][SIZE])
259	{
260		uint8_t x, y;
261		uint8_t count = 0;
262		for (x = 0; x < SIZE; x++)
263		{
264			for (y = 0; y < SIZE; y++)
265			{
266				if (board[x][y] == 0)
267				{
268					count++;
269				}
270			}
271		}
272		return count;
273	}
274	
275	bool gameEnded(uint8_t board[SIZE][SIZE])
276	{
277		bool ended = true;
278		if (countEmpty(board) > 0)
279			return false;
280		if (findPairDown(board))
281			return false;
282		rotateBoard(board);
283		if (findPairDown(board))
284			ended = false;
285		rotateBoard(board);
286		rotateBoard(board);
287		rotateBoard(board);
288		return ended;
289	}
