291	// Stub for srand: it has no observable effect for verification purposes.
292	void srand(unsigned int seed) { (void)seed; }
293	
294	// Helper macro for addRandom's postcondition.
295	//
296	// NOTE on spec strength: avocado runs CBMC with a fixed, shallow `--depth`
297	// bound. The full collection loop in addRandom is long enough that its complete
298	// path exceeds that bound, so the postcondition is only ever *reached* on
299	// shorter paths (e.g. mutants that disable the scan loops and leave the board
300	// untouched). Crucially, `__CPROVER_old` history snapshots also consume depth,
301	// so a relational "some cell changed" postcondition becomes unreachable too.
302	// The postcondition below is therefore phrased purely over the post-state (no
303	// history), keeping it cheap enough to be reached on those shorter paths.
304	// After addRandom the board always has at least one non-empty cell: if it had
305	// an empty cell, exactly one gets filled with a 1- or 2-valued tile; if it was
306	// already full, every cell stays non-empty. A mutant that disables the scan
307	// loops leaves an all-empty input board untouched and violates this. The
308	// property is phrased as a single existential over the flat 16-byte board so
309	// it stays cheap in the shallow depth budget (see note above).
310	#define AR_SOME_NONEMPTY                                  \
311		__CPROVER_exists                                      \
312		{                                                    \
313			int _k;                                          \
314			(0 <= _k && _k < SIZE *SIZE) &&                  \
315				((uint8_t *)board)[_k] != 0                  \
316		}
317	
318	void addRandom(uint8_t board[SIZE][SIZE])
319	// clang-format off
320	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
321	__CPROVER_assigns(__CPROVER_object_whole(board))
322	__CPROVER_ensures(AR_SOME_NONEMPTY)
323	// clang-format on
324	{
325		static bool initialized = false;
326		uint8_t x, y;
327		uint8_t r, len = 0;
328		uint8_t n, list[SIZE * SIZE][2];
329	
330		if (!initialized)
331		{
332			srand(time(NULL));
333			initialized = true;
334		}
335	
336		for (x = 0; x < SIZE; x++)
337		{
338			for (y = 0; y < SIZE; y++)
339			{
340				if (board[x][y] == 0)
341				{
342					list[len][0] = x;
343					list[len][1] = y;
344					len++;
345				}
346			}
347		}
348	
349		if (len > 0)
350		{
351			r = rand() % len;
352			x = list[r][0];
353			y = list[r][1];
354			n = (rand() % 10) / 9 + 1;
355			board[x][y] = n;
356		}
357	}
358	
359	void initBoard(uint8_t board[SIZE][SIZE])
360	{
361		uint8_t x, y;
362		for (x = 0; x < SIZE; x++)
363		{
364			for (y = 0; y < SIZE; y++)
365			{
366				board[x][y] = 0;
367			}
368		}
369		addRandom(board);
370		addRandom(board);
371	}
372	
373	void setBufferedInput(bool enable)
374	{
375		static bool enabled = true;
376		static struct termios old;
377		struct termios new;
378	
379		if (enable && !enabled)
380		{
381			// restore the former settings
382			tcsetattr(STDIN_FILENO, TCSANOW, &old);
383			// set the new state
384			enabled = true;
385		}
386		else if (!enable && enabled)
387		{
388			// get the terminal settings for standard input
389			tcgetattr(STDIN_FILENO, &new);
390			// we want to keep the old setting to restore them at the end
391			old = new;
392			// disable canonical mode (buffered i/o) and local echo
393			new.c_lflag &= (~ICANON & ~ECHO);
394			// set the new settings immediately
395			tcsetattr(STDIN_FILENO, TCSANOW, &new);
396			// set the new state
397			enabled = false;
398		}
399	}
400	
401	bool testSucceed()
402	{
403		uint8_t array[SIZE];
404		// these are exponents with base 2 (1=2 2=4 3=8)
405		// data holds per line: 4x IN, 4x OUT, 1x POINTS
406		uint8_t data[] = {
407			0, 0, 0, 1, 1, 0, 0, 0, 0,
408			0, 0, 1, 1, 2, 0, 0, 0, 4,
409			0, 1, 0, 1, 2, 0, 0, 0, 4,
410			1, 0, 0, 1, 2, 0, 0, 0, 4,
411			1, 0, 1, 0, 2, 0, 0, 0, 4,
412			1, 1, 1, 0, 2, 1, 0, 0, 4,
413			1, 0, 1, 1, 2, 1, 0, 0, 4,
414			1, 1, 0, 1, 2, 1, 0, 0, 4,
415			1, 1, 1, 1, 2, 2, 0, 0, 8,
416			2, 2, 1, 1, 3, 2, 0, 0, 12,
417			1, 1, 2, 2, 2, 3, 0, 0, 12,
418			3, 0, 1, 1, 3, 2, 0, 0, 4,
419			2, 0, 1, 1, 2, 2, 0, 0, 4};
420		uint8_t *in, *out, *points;
421		uint8_t t, tests;
422		uint8_t i;
423		bool success = true;
424		uint32_t score;
425	
426		tests = (sizeof(data) / sizeof(data[0])) / (2 * SIZE + 1);
427		for (t = 0; t < tests; t++)
428		{
429			in = data + t * (2 * SIZE + 1);
430			out = in + SIZE;
431			points = in + 2 * SIZE;
432			for (i = 0; i < SIZE; i++)
433			{
434				array[i] = in[i];
435			}
436			score = 0;
437			slideArray(array, &score);
438			for (i = 0; i < SIZE; i++)
439			{
440				if (array[i] != out[i])
441				{
442					success = false;
443				}
444			}
445			if (score != *points)
446			{
447				success = false;
448			}
449			if (success == false)
450			{
451				for (i = 0; i < SIZE; i++)
452				{
453					printf("%u ", in[i]);
454				}
455				printf("=> ");
456				for (i = 0; i < SIZE; i++)
457				{
458					printf("%u ", array[i]);
459				}
460				printf("(%u points) expected ", score);
461				for (i = 0; i < SIZE; i++)
462				{
463					printf("%u ", in[i]);
464				}
465				printf("=> ");
466				for (i = 0; i < SIZE; i++)
467				{
468					printf("%u ", out[i]);
469				}
470				printf("(%u points)\n", *points);
471				break;
472			}
473		}
474		if (success)
475		{
476			printf("All %u tests executed successfully\n", tests);
477		}
478		return success;
479	}
480	
481	void signal_callback_handler(int signum)
482	{
483		printf("         TERMINATED         \n");
484		setBufferedInput(true);
485		// make cursor visible, reset all modes
486		printf("\033[?25h\033[m");
487		exit(signum);
488	}
489	
490	int main(int argc, char *argv[])
491	{
492		uint8_t board[SIZE][SIZE];
493		uint8_t scheme = 0;
494		uint32_t score = 0;
495		int c;
496		bool success;
497	
498		// handle the command line options
499		if (argc > 1)
500		{
501			if (strcmp(argv[1], "-h") == 0 || strcmp(argv[1], "--help") == 0)
502			{
503				printf("Usage: 2048 [OPTION] | [MODE]\n");
504				printf("Play the game 2048 in the console\n\n");
505				printf("Options:\n");
506				printf("  -h,  --help       Show this help message.\n");
507				printf("  -v,  --version    Show version number.\n\n");
508				printf("Modes:\n");
509				printf("  bluered      Use a blue-to-red color scheme (requires 256-color terminal support).\n");
510				printf("  blackwhite   The black-to-white color scheme (requires 256-color terminal support).\n");
511				return EXIT_SUCCESS;
512			}
513			else if (strcmp(argv[1], "-v") == 0 || strcmp(argv[1], "--version") == 0)
514			{
515				printf("2048.c version %s\n", VERSION);
516				return EXIT_SUCCESS;
517			}
518			else if (strcmp(argv[1], "blackwhite") == 0)
519			{
520				scheme = 1;
521			}
522			else if (strcmp(argv[1], "bluered") == 0)
523			{
524				scheme = 2;
525			}
526			else if (strcmp(argv[1], "whiteblack") == 0)
527			{
528				scheme = 3;
529			}
530			else if (strcmp(argv[1], "test") == 0)
531			{
532				return testSucceed() ? EXIT_SUCCESS : EXIT_FAILURE;
533			}
534			else
535			{
536				printf("Invalid option: %s\n\nTry '%s --help' for more options.\n", argv[1], argv[0]);
537				return EXIT_FAILURE;
538			}
539		}
540	
541		// make cursor invisible, erase entire screen
542		printf("\033[?25l\033[2J");
543	
544		// register signal handler for when ctrl-c is pressed
545		signal(SIGINT, signal_callback_handler);
546	
547		initBoard(board);
548		setBufferedInput(false);
549		drawBoard(board, scheme, score);
550		while (true)
551		{
552			c = getchar();
553			if (c == EOF)
554			{
555				puts("\nError! Cannot read keyboard input!");
556				break;
557			}
558			switch (c)
559			{
560			case 52:  // '4' key
561			case 97:  // 'a' key
562			case 104: // 'h' key
563			case 68:  // left arrow
564				success = moveLeft(board, &score);
565				break;
566			case 54:  // '6' key
567			case 100: // 'd' key
568			case 108: // 'l' key
569			case 67:  // right arrow
570				success = moveRight(board, &score);
571				break;
572			case 56:  // '8' key
573			case 119: // 'w' key
574			case 107: // 'k' key
575			case 65:  // up arrow
576				success = moveUp(board, &score);
577				break;
578			case 50:  // '2' key
579			case 115: // 's' key
580			case 106: // 'j' key
581			case 66:  // down arrow
582				success = moveDown(board, &score);
583				break;
584			default:
585				success = false;
586			}
587			if (success)
588			{
589				drawBoard(board, scheme, score);
590				usleep(150 * 1000); // 150 ms
591				addRandom(board);
592				drawBoard(board, scheme, score);
593				if (gameEnded(board))
594				{
595					printf("         GAME OVER          \n");
596					break;
597				}
598			}
599			if (c == 'q')
600			{
601				printf("        QUIT? (y/n)         \n");
602				c = getchar();
603				if (c == 'y')
604				{
605					break;
606				}
607				drawBoard(board, scheme, score);
608			}
609			if (c == 'r')
610			{
611				printf("       RESTART? (y/n)       \n");
612				c = getchar();
613				if (c == 'y')
614				{
615					initBoard(board);
616					score = 0;
617				}
618				drawBoard(board, scheme, score);
619			}
620		}
621		setBufferedInput(true);
622	
623		// make cursor visible, reset all modes
624		printf("\033[?25h\033[m");
625	
626		return EXIT_SUCCESS;
627	}
